class PaymentService {
  _maskCardNumber(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (cleaned.length < 4) return '****';
    return `****${cleaned.slice(-4)}`;
  }

  _validateCardData(cardData) {
    if (!cardData.cardNumber || !cardData.expiryMonth || !cardData.expiryYear) {
      throw new Error('Invalid card data: missing required fields');
    }

    const cleaned = cardData.cardNumber.replace(/\s/g, '');
    if (cleaned.length < 13 || cleaned.length > 19) {
      throw new Error('Invalid card number length');
    }

    if (!/^\d+$/.test(cleaned)) {
      throw new Error('Card number must contain only digits');
    }
  }

  async savePaymentInfo(cardData) {
    this._validateCardData(cardData);

    const securePaymentData = {
      id: cardData.id || `card_${Date.now()}`,
      cardNumber: cardData.cardNumber.replace(/\s/g, ''),
      maskedNumber: this._maskCardNumber(cardData.cardNumber),
      expiryMonth: cardData.expiryMonth,
      expiryYear: cardData.expiryYear,
      cardholderName: cardData.cardholderName,
      cardType: this._detectCardType(cardData.cardNumber),
      billingAddress: cardData.billingAddress || null,
      createdAt: new Date().toISOString(),
      fingerprint: encryptionService.hashData(cardData.cardNumber.replace(/\s/g, '')),
    };

    const existingCards = await this.getAllPaymentMethods();
    const updatedCards = [
      ...existingCards.filter((c) => c.fingerprint !== securePaymentData.fingerprint),
      securePaymentData,
    ];

    await secureStorage.setItem(StorageKeys.PAYMENT_INFO, updatedCards);

    return {
      id: securePaymentData.id,
      maskedNumber: securePaymentData.maskedNumber,
      cardType: securePaymentData.cardType,
      expiryMonth: securePaymentData.expiryMonth,
      expiryYear: securePaymentData.expiryYear,
      cardholderName: securePaymentData.cardholderName,
    };
  }

  async getAllPaymentMethods() {
    const cards = await secureStorage.getItem(StorageKeys.PAYMENT_INFO);
    return cards || [];
  }

  async getPaymentMethodSummaries() {
    const cards = await this.getAllPaymentMethods();
    return cards.map((card) => ({
      id: card.id,
      maskedNumber: card.maskedNumber,
      cardType: card.cardType,
      expiryMonth: card.expiryMonth,
      expiryYear: card.expiryYear,
      cardholderName: card.cardholderName,
    }));
  }

  async getFullPaymentMethod(cardId) {
    const cards = await this.getAllPaymentMethods();
    return cards.find((c) => c.id === cardId) || null;
  }

  async removePaymentMethod(cardId) {
    const cards = await this.getAllPaymentMethods();
    const updatedCards = cards.filter((c) => c.id !== cardId);
    await secureStorage.setItem(StorageKeys.PAYMENT_INFO, updatedCards);
    return true;
  }

  async clearAllPaymentMethods() {
    await secureStorage.removeItem(StorageKeys.PAYMENT_INFO);
  }

  _detectCardType(cardNumber) {
    const cleaned = cardNumber.replace(/\s/g, '');
    if (/^4/.test(cleaned)) return 'visa';
    if (/^5[1-5]/.test(cleaned) || /^2[2-7]/.test(cleaned)) return 'mastercard';
    if (/^3[47]/.test(cleaned)) return 'amex';
    if (/^6(?:011|5)/.test(cleaned)) return 'discover';
    if (/^35(?:2[89]|[3-8])/.test(cleaned)) return 'jcb';
    if (/^3(?:0[0-5]|[68])/.test(cleaned)) return 'diners';
    return 'unknown';
  }
}

