import secureStorage, { StorageKeys } from '../utils/secureStorage';

class AuthTokenService {
  async saveTokens(tokens) {
    const tokenData = {
      accessToken: tokens.accessToken,
      refreshToken: tokens.refreshToken,
      tokenType: tokens.tokenType || 'Bearer',
      expiresIn: tokens.expiresIn,
      expiresAt: tokens.expiresAt || (tokens.expiresIn
        ? new Date(Date.now() + tokens.expiresIn * 1000).toISOString()
        : null),
      scope: tokens.scope || null,
      savedAt: new Date().toISOString(),
    };

    await secureStorage.multiSet([
      [StorageKeys.AUTH_TOKEN, tokenData],
      [StorageKeys.AUTH_REFRESH_TOKEN, {
        refreshToken: tokens.refreshToken,
        savedAt: tokenData.savedAt,
      }],
    ]);

    return tokenData;
  }

  async getAccessToken() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return null;

    if (this._isTokenExpired(tokenData)) {
      return null;
    }

    return tokenData.accessToken;
  }

  async getTokenData() {
    return await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
  }

  async getRefreshToken() {
    const refreshData = await secureStorage.getItem(StorageKeys.AUTH_REFRESH_TOKEN);
    return refreshData ? refreshData.refreshToken : null;
  }

  async getAuthorizationHeader() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData || this._isTokenExpired(tokenData)) {
      return null;
    }

    return `${tokenData.tokenType} ${tokenData.accessToken}`;
  }

  async isAuthenticated() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) return false;

    if (this._isTokenExpired(tokenData)) {
      const refreshToken = await this.getRefreshToken();
      return refreshToken !== null;
    }

    return true;
  }

  async updateAccessToken(newAccessToken, expiresIn) {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData) {
      throw new Error('No existing token data found');
    }

    const updatedTokenData = {
      ...tokenData,
      accessToken: newAccessToken,
      expiresIn: expiresIn || tokenData.expiresIn,
      expiresAt: expiresIn
        ? new Date(Date.now() + expiresIn * 1000).toISOString()
        : tokenData.expiresAt,
      savedAt: new Date().toISOString(),
    };

    await secureStorage.setItem(StorageKeys.AUTH_TOKEN, updatedTokenData);
    return updatedTokenData;
  }

  async clearTokens() {
    await Promise.all([
      secureStorage.removeItem(StorageKeys.AUTH_TOKEN),
      secureStorage.removeItem(StorageKeys.AUTH_REFRESH_TOKEN),
    ]);
  }

  _isTokenExpired(tokenData) {
    if (!tokenData.expiresAt) return false;

    const expiresAt = new Date(tokenData.expiresAt);
    const bufferMs = 60 * 1000; // 1 minute buffer
    return new Date() >= new Date(expiresAt.getTime() - bufferMs);
  }

  async getTokenExpiryInfo() {
    const tokenData = await secureStorage.getItem(StorageKeys.AUTH_TOKEN);
    if (!tokenData || !tokenData.expiresAt) {
      return null;
    }

    const expiresAt = new Date(tokenData.expiresAt);
    const now = new Date();
    const remainingMs = expiresAt.getTime() - now.getTime();

    return {
      expiresAt: tokenData.expiresAt,
      isExpired: remainingMs <= 0,
      remainingSeconds: Math.max(0, Math.floor(remainingMs / 1000)),
      remainingMinutes: Math.max(0, Math.floor(remainingMs / 60000)),
    };
  }
}

