// hooks/useSecureStorage.js
import { useState, useCallback, useEffect } from 'react';
import secureStorage from '../utils/secureStorage';

export function useSecureStorage(key, initialValue = null) {
  const [storedValue, setStoredValue] = useState(initialValue);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const loadValue = useCallback(async () => {
    try {
      setLoading(true);
      setError(null);
      const value = await secureStorage.getItem(key);
      setStoredValue(value !== null ? value : initialValue);
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage load error for key "${key}":`, err);
    } finally {
      setLoading(false);
    }
  }, [key, initialValue]);

  useEffect(() => {
    loadValue();
  }, [loadValue]);

  const setValue = useCallback(
    async (value) => {
      try {
        setError(null);
        const valueToStore = value instanceof Function ? value(storedValue) : value;
        await secureStorage.setItem(key, valueToStore);
        setStoredValue(valueToStore);
        return true;
      } catch (err) {
        setError(err);
        console.error(`useSecureStorage set error for key "${key}":`, err);
        return false;
      }
    },
    [key, storedValue]
  );

  const removeValue = useCallback(async () => {
    try {
      setError(null);
      await secureStorage.removeItem(key);
      setStoredValue(initialValue);
      return true;
    } catch (err) {
      setError(err);
      console.error(`useSecureStorage remove error for key "${key}":`, err);
      return false;
    }
  }, [key, initialValue]);

  return {
    value: storedValue,
    setValue,
    removeValue,
    refresh: loadValue,
    loading,
    error,
  };
}

export default useSecureStorage;


// hooks/useAuth.js
import { useState, useCallback, useEffect } from 'react';
import authTokenService from '../services/authTokenService';

export function useAuth() {
  const [isAuthenticated, setIsAuthenticated] = useState(false);
  const [loading, setLoading] = useState(true);
  const [tokenInfo, setTokenInfo] = useState(null);

  const checkAuth = useCallback(async () => {
    try {
      setLoading(true);
      const authenticated = await authTokenService.isAuthenticated();
      setIsAuthenticated(authenticated);

      if (authenticated) {
        const expiryInfo = await authTokenService.getTokenExpiryInfo();
        setTokenInfo(expiryInfo);
      } else {
        setTokenInfo(null);
      }
    } catch (error) {
      console.error('Auth check failed:', error);
      setIsAuthenticated(false);
      setTokenInfo(null);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    checkAuth();
  }, [checkAuth]);

  const login = useCallback(async (tokens) => {
    try {
      await authTokenService.saveTokens(tokens);
      setIsAuthenticated(true);
      const expiryInfo = await authTokenService.getTokenExpiryInfo();
      setTokenInfo(expiryInfo);
      return true;
    } catch (error) {
      console.error('Login failed:', error);
      return false;
    }
  }, []);

  const logout = useCallback(async () => {
    try {
      await authTokenService.clearTokens();
      setIsAuthenticated(false);
      setTokenInfo(null);
      return true;
    } catch (error) {
      console.error('Logout failed:', error);
      return false;
    }
  }, []);

  const getAuthHeader = useCallback(async () => {
    return await authTokenService.getAuthorizationHeader();
  }, []);

  return {
    isAuthenticated,
    loading,
    tokenInfo,
    login,
    logout,
    getAuthHeader,
    refreshAuthState: checkAuth,
  };
}

export default useAuth;


